let configEntries = page.variables.allConfigValues;
const configMap = new Map();

  // Iterate over each item in the input array.
  configEntries.forEach(item => {
    // 1. Extract all the objects where “dimension“ array size is not 0
    //    And ensure 'dimensions' property itself exists and is an array.
    if (item.dimensions && Array.isArray(item.dimensions) && item.dimensions.length > 0) {
      // 2. Consider the first object in the “dimension“ array as a primary key named CONFIG_KEY_NAME.
      //    Use optional chaining (?.) for safe access, though per problem description,
      //    if length > 0, dimension[0] and its string_value are expected to exist.
      const configKeyName = item.dimensions[0]?.string_value;

      // Ensure configKeyName is valid before processing further
      if (configKeyName) {
        // Prepare the 'condition' object for the current item.
        // Use optional chaining (?.) and nullish coalescing (??)
        // for robust index validation and providing default `undefined` for missing data.
        let appVersion = item.dimensions[2]?.string_value ?? "";
        if(appVersion.includes("range:")) {
          appVersion = appVersion.replace("range:", '');
        }
        const condition = {
          value: item.value?.string_value,
          appChannel: item.dimensions[1]?.string_value ?? "", // dimension at index 1 for appChannel
          appVersion: appVersion, // dimension at index 2 for appVersion
          cityIds: item.dimensions[3]?.string_value ?? "",   // dimension at index 3 for cityIds
          createdBy: `${item.created_by?.email_id || "NA"}`,
          createdAt: `${formatTimestamp(item.created_time?.seconds) }`  // updated_time.seconds
        };

        // 3. For equal CONFIG_KEY_NAME, read other objects from the dimension array.
        //    Create a map (grouping) of this.
        if (configMap.has(configKeyName)) {
          // If the configKeyName already exists in the map, add the new condition to its array.
          configMap.get(configKeyName).push(condition);
        } else {
          // If it's a new configKeyName, create a new array with the current condition.
          configMap.set(configKeyName, [condition]);
        }
      }
    }
  });

  // 4. Create an output JSON array of the specified format.
  // Convert the Map into the desired array format.
  const outputArray = Array.from(configMap.entries()).map(([key, value]) => ({
    configKeyName: key,
    conditions: value,
  }));
//updateConfigEntries.setValue(outputArray);
await actions.setPageVariable("updateConfigEntries",outputArray)

function formatTimestamp(timestamp) {
  try {
    const date = new Date(parseInt(timestamp) * 1000);
    if (isNaN(date.getTime())) return 'Invalid Date';
    const day = String(date.getDate()).padStart(2, '0');
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = date.getFullYear();
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const seconds = String(date.getSeconds()).padStart(2, '0');
    return `${day}/${month}/${year} \n at ${hours}:${minutes}:${seconds}`;
  } catch (error) {
    return '';
  }
}
